INSERT INTO streets (name, era, year, description) VALUES
('ул. Ленина', 'Советский период', '1924', 'Главная улица Благовещенска – имени Ленина. Первоначально она называлась Большой, а от района драмтеатра и далее на запад – Суворовской. 24 января 1924 года на траурном заседании горсовета рабочих и депутатов в связи со смертью вождя решили назвать улицу его именем. До 1924 года называлась Большой улицей — главной торговой артерией дореволюционного Благовещенска.'),
('ул. Горького', 'Советский период', '1937', 'Улица Иркутская ныне Горького, была проложена параллельно реке Амур вслед за Набережной, Большой, Зеской и Амурской. Отличалась даже для Благовещенска непривычной шириной и почти идеальной прямизной, протянувшись с Востока на Запад, показывая направление на Иркутск. Из города Иркутска, который был столицей Восточно-Сибирской губернии и резиденцией генерал-губернатора Н.Н. Муравьева-Амурского, в город Благовещенск поставлялось продовольствие, строительные материалы и прочее. Не случайно, в знак признания особого значения г. Иркутска для Приамурья, одна из первых улиц молодого города получает имя Иркутской. После прихода к власти большевиков, в 1925 года решение городского Совета, улица Иркутская была переименована в Кубяковскую в честь Николая Афанасьевича Кубяка – видного деятеля коммунистической партии. Его имя улица носила до 1937 года, когда Н.А. Кубяк был необоснованно репрессирован, объявлен врагом народа и расстрелян. Кубяковская улица была переименована в улицу Горького, в честь писателя А.М. Горького, незадолго перед этим скончавшегося в Горках, под Москвой.'),
('пер. Рёлочный', 'Дореволюционный', '1857', 'Солдаты линейного батальона, построив мазанки, а затем и первый деревянный дом, служивший часовней, образовали первую улицу города, названную в последствии Рёлочной — по месту нахождения первого дома, построенного в 1857–59 годах на возвышенном месте – рёлке. С этой улицы и началось строительство города. В 1857 поселение города Благовещенска было перенесено на возвышенное место – релку, где и была основана первая улица Релочная, ныне переулок Релочный. Название такое она получила от того, что первые бараки, построенные на ней, располагались вдоль возвышенной релки.'),
('ул. Партизанская', 'Советский период', '1920', 'Вторая улица в городе была наименована Казачья, сегодня это улица Партизанская.'),
('ул. Пионерская', 'Советский период', '1920', 'Пионерская была когда-то Благовещенской – название ее, как и всей станицы, пошло от храма Благовещенья Пресвятой Богородицы.'),
('ул. имени 50-летия Октября', 'Советский период', '1967', 'Улица имени 50-летия Октября раньше была Садовой, но на пятую годовщину Красной Армии, в феврале 1923 года, стала называться Красноармейской. А 4 ноября 1967 года Красноармейская получила нынешнее свое название – имени 50-летия Октября. Эта улица одна из немногих в Благовещенске, где прошлое накрепко переплелось с настоящим. В 1923 году «Амурская правда» объяснила причину смены названия: «Переименовывается эта улица, по которой красноармейцы уходили умирать на сопки Даурии, под Казакевичево, Красную речку… По этой же улице возвращались красноармейцы–победители из Забайкалья, Приморья и других славных мест боя». А 44 года спустя, 4 ноября 1967 года, в 50-ю годовщину Великого Октября улицу вновь переименовали.'),
('ул. Фрунзе', 'Советский период', '1920', 'На улице Фрунзе раньше красовались таблички «Муравьевская». Благодаря Н.Н. Муравьеву, Приамурский край был присоединен к России. За это государь император удостоил его графского титула и присоединил к его фамилии дополнение Амурский. Отсюда и имя другой улицы – Графской.'),
('ул. Кузнечная', 'Дореволюционный', '1858', 'Улица Кузнечная сохранила свое старое название: на берегу Амура в районе этой улицы была казачья кузница. Работала она недолго, но сыграла в жизни поселенцев не последнюю роль.'),
('ул. Драгошевского', 'Советский период', '1920', 'Улица Драгошевского (р-н Тайваня) получила имя большевика Генриха Драгошевского. С началом Мухинского восстания (освободительного крестьянского восстания против иностранных интервентов и белогвардейцев в начале 1919 года) в Амурской области он был избран командиром партизанской армии. Она совершила героический рейд по Зейско-Буреинской равнине, разбив японо-белогвардейский отряд под населенными пунктами.'),
('ул. Мухина', 'Советский период', '1920', '24 марта 1920 года улица Офицерская была переименована в улицу Мухина – в память о тех, кто участвовал в освобождении области от японских интервентов. Фёдор Никанорович Мухин занимал должность председателя Совета депутатов области. На этом посту он провел радикальную социализацию: принял решение о национализации заводов, фабрик и прочей частной собственности. Мухин являлся создателем большевистской организации, которая готовила восстание против колчаковского режима и японских интервентов в феврале 1918 — марте 1919 г. Восстание, поднявшее народные силы, получило название Мухинского в честь организатора.'),
('ул. Комсомольская', 'Советский период', '1920', 'Улица Никольская – ныне Комсомольская – свое первоначальное название получила в честь первой в городе Свято-Никольской церкви. 20 октября 1920 года в здании областного драматического театра состоялся I съезд «Красной молодежи» Амура, на котором и решили переименовать Никольскую в Комсомольскую.'),
('ул. Шевченко', 'Советский период', '1954', 'До 1954 года улица Шевченко носила название Мастерская, в связи с размещением на ней различных мастерских. В 1954 году улица переименована в честь Шевченко Тараса Григорьевича (1814–1861) — украинского поэта, прозаика, мыслителя, живописца, графика, этнографа, общественного деятеля.'),
('ул. Ломоносова', 'Советский период', '1964', 'Коммерческая улица в 1931 году стала улицей Декабрьских восстаний, а в 1964 году получила новое название — имени Ломоносова. Переименовал ее своим постановлением горисполком 27 января.'),
('ул. Чехова', 'Советский период', '1973', 'Улица Чехова называлась Кожевенной. В различных краеведческих источниках были обнаружены разночтения о дате переименования улицы. Изучив литературу по данному вопросу, исследователи пришли к выводу, что верной датой переименования улицы Кожевенной в улицу Чехова является 1973 год. Следующий раз вопрос переименования улиц поднимали в 1990 году: тогда депутаты решили вернуть улицам дореволюционные названия, предлагалось делать это по одной улице в год, но из-за отсутствия средств постановление не было исполнено.'),
('ул. Богдана Хмельницкого', 'Советский период', '1954', 'Улица, начинающаяся у Чуринской площади (ныне площадь Победы), называлась Торговой. В честь воссоединения Украины с Россией 20 мая 1954 года она стала носить имя Богдана Хмельницкого.'),
('пер. Уралова', 'Советский период', '1962', 'В 1948–1962 годах Амурский театр драмы возглавлял заслуженный деятель искусств, воспитавший целую плеяду актеров, работавших во многих театрах Москвы и Санкт-Петербурга – Николай Уралов (1899–1964). Амурский театр при Уралове гремел: он с блеском поставил на местной сцене более 60 классических пьес русских, советских и зарубежных драматургов, а также сыграл более 50 ролей. Переулок Почтамтский переименован в 1962 г. в переулок имени Уралова, заслуженного артиста, главного режиссера амурского театра драмы.'),
('ул. Шимановского', 'Советский период', '1957', 'Дата рождения улицы Шимановского — 28 ноября 1957 года. До этого времени она называлась в честь сподвижника Г.И. Невельского по Амурской экспедиции — Буссевской. Владимир Иванович Шимановский был революционером: многое сделал для обеспечения перевозки военных грузов, а благодаря правильному приведению вооруженных сил в готовность был подавлен Гамовский мятеж — антибольшевистское восстание под руководством атамана И.М. Гамова. Однако улица не сразу носила фамилию Шимановского: перед этим она была названа в честь военного губернатора Николая Буссе, позднее носила имя полководца Семена Буденного.'),
('ул. Пушкина', 'Советский период', '1973', 'Улица Бурхановская (свое название получила от реки Бурхановка) была переименована в 1973 году в улицу имени Пушкина, в честь великого русского поэта А.С. Пушкина.'),
('ул. Конная', 'Дореволюционный', '1858', 'Улица Конная вела к ипподрому, поэтому и названа именно так, а не иначе.'),
('ул. Трудовая', 'Советский период', '1974', 'Улица Трудовая названа в честь ордена «Трудовой славы», который был учрежден в январе 1974 года. Им награждались рабочие и колхозники при условии долголетней работы и высокой производительности труда.'),
('ул. Заводская', 'Дореволюционный', '1858', 'Наименование улицы Заводской связано с основанием Н.С. Львовым чугунолитейного завода (позже – завод Октябрьской революции). Рядом также появились улицы Литейная и Рабочая, названия которых также отражают историю этого промышленного района.'),
('ул. Литейная', 'Дореволюционный', '1858', 'Наименование улицы Литейной связано с основанием Н.С. Львовым чугунолитейного завода (позже – завод Октябрьской революции). Рядом также располагаются улицы Заводская и Рабочая.'),
('ул. Рабочая', 'Дореволюционный', '1858', 'Наименование улицы Рабочей связано с основанием Н.С. Львовым чугунолитейного завода (позже – завод Октябрьской революции). Рядом также располагаются улицы Заводская и Литейная.'),
('ул. Калинина', 'Советский период', '1946', 'Улица названа в честь Михаила Ивановича Калинина — советского государственного деятеля, председателя ВЦИК. До переименования носила название Институтской улицы.'),
('ул. Амурская', 'Дореволюционный', '1858', 'Одна из старейших улиц Благовещенска, сохранившая своё историческое название. Названа в честь реки Амур, на берегу которой стоит город. Была главной улицей в первые годы существования поселения.');
